UPDATE u_user_points 
SET current_balance = current_balance + #{amount,jdbcType=INTEGER},
    total_earned = total_earned + #{amount,jdbcType=INTEGER},
    last_update_time = NOW()
WHERE user_id = #{userId,jdbcType=VARCHAR} 
  AND points_type_id = #{pointsTypeId,jdbcType=BIGINT}

UPDATE u_user_points 
SET current_balance = current_balance - #{amount,jdbcType=INTEGER},
    total_spent = total_spent + #{amount,jdbcType=INTEGER},
    last_update_time = NOW()
WHERE user_id = #{userId,jdbcType=VARCHAR} 
  AND points_type_id = #{pointsTypeId,jdbcType=BIGINT}
  AND current_balance >= #{amount,jdbcType=INTEGER}

UPDATE u_user_points 
SET frozen_points = frozen_points + #{amount,jdbcType=INTEGER},
    last_update_time = NOW()
WHERE user_id = #{userId,jdbcType=VARCHAR} 
  AND points_type_id = #{pointsTypeId,jdbcType=BIGINT}

UPDATE u_user_points 
SET frozen_points = frozen_points - #{amount,jdbcType=INTEGER},
    last_update_time = NOW()
WHERE user_id = #{userId,jdbcType=VARCHAR} 
  AND points_type_id = #{pointsTypeId,jdbcType=BIGINT}
  AND frozen_points >= #{amount,jdbcType=INTEGER}

UPDATE u_user_points 
SET frozen_points = frozen_points - #{amount,jdbcType=INTEGER},
    current_balance = current_balance + #{amount,jdbcType=INTEGER},
    total_earned = total_earned + #{amount,jdbcType=INTEGER},
    last_update_time = NOW()
WHERE user_id = #{userId,jdbcType=VARCHAR} 
  AND points_type_id = #{pointsTypeId,jdbcType=BIGINT}
  AND frozen_points >= #{amount,jdbcType=INTEGER}

